CREATE TABLE IF NOT EXISTS atrakcii (
    id           BIGSERIAL PRIMARY KEY,
    naslov       VARCHAR(255)     NOT NULL,
    lokacija     VARCHAR(100)     NOT NULL,
    cena_od_den  NUMERIC(10, 2),
    status       VARCHAR(50),
    link         VARCHAR(512),
    slika        VARCHAR(512),
    opis         TEXT,
    created_at   TIMESTAMP        NOT NULL DEFAULT NOW(),
    updated_at   TIMESTAMP        NOT NULL DEFAULT NOW()
    );

CREATE TABLE IF NOT EXISTS atrakcija_tagovi (
    atrakcija_id BIGINT NOT NULL,
    tag VARCHAR(255),
    CONSTRAINT fk_atrakcija_tagovi
    FOREIGN KEY (atrakcija_id)
    REFERENCES atrakcii(id)
    ON DELETE CASCADE
    );





-- Reset sequence so future inserts don't collide with seeded IDs
SELECT setval('atrakcii_id_seq', (SELECT MAX(id) FROM atrakcii));